SELECT
    DATE_TRUNC('hour', ht.collected_at) as timestamp,
    AVG(ht.avg_cache_hit_ratio) as cache_hit_ratio
FROM hot_table_agg ht
INNER JOIN monitor_database d ON ht.database_id = d.database_id
WHERE d.instance_id = #{instanceId}
  AND ht.database_id = #{databaseId}
  AND ht.collected_at BETWEEN #{startTime} AND #{endTime}
GROUP BY DATE_TRUNC('hour', ht.collected_at)
ORDER BY timestamp

SELECT ht.hot_table_raw_id, ht.schema_name, ht.table_name, ht.table_size, ht.seq_scan, ht.seq_tup_read, ht.idx_scan, ht.idx_tup_fetch, ht.n_tup_ins, ht.n_tup_upd, ht.n_tup_del, ht.n_tup_hot_upd, ht.n_live_tup, ht.n_dead_tup, ht.bloat_percent, ht.last_vacuum, ht.last_autovacuum, ht.heap_blks_read, ht.heap_blks_hit, CASE WHEN ht.bloat_percent >= 30 THEN '위험' WHEN ht.bloat_percent >= 15 THEN '주의' ELSE '정상' END as status FROM hot_table_raw ht INNER JOIN monitor_database d ON ht.database_id = d.database_id WHERE d.instance_id = #{instanceId} AND ht.database_id = #{databaseId} AND ht.collected_at BETWEEN #{startTime} AND #{endTime}
AND CASE WHEN ht.bloat_percent >= 30 THEN '위험' WHEN ht.bloat_percent >= 15 THEN '주의' ELSE '정상' END IN
#{status}
ORDER BY ht.collected_at DESC, ht.table_size DESC
